'use client';

import { useState } from 'react';
import { useAuth } from '@/contexts/AuthContext';
import { useRouter } from 'next/navigation';
import Link from 'next/link';
import { motion } from 'framer-motion';
import { Loader2, AlertCircle, ShieldCheck } from 'lucide-react';

export default function LoginPage() {
    const [email, setEmail] = useState('');
    const [password, setPassword] = useState('');
    const [error, setError] = useState('');

    const { login, isLoading } = useAuth();
    const router = useRouter();

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setError('');

        try {
            await login({ email, password });
            router.push('/');
        } catch (err) {
            setError('Invalid email or password');
        }
    };

    return (
        <div className="min-h-screen bg-slate-50 flex items-center justify-center p-4">
            <motion.div
                initial={{ opacity: 0, y: 20 }}
                animate={{ opacity: 1, y: 0 }}
                className="bg-white rounded-2xl shadow-xl w-full max-w-4xl overflow-hidden flex flex-col md:flex-row"
            >
                {/* Visual Side */}
                <div className="hidden md:flex flex-col justify-between p-12 bg-gradient-to-br from-blue-600 to-indigo-700 text-white w-2/5 relative overflow-hidden">
                    <div className="relative z-10">
                        <div className="w-12 h-12 bg-white/10 backdrop-blur-lg rounded-xl flex items-center justify-center mb-8 shadow-inner border border-white/20">
                            <span className="font-bold text-xl">D</span>
                        </div>
                        <h2 className="text-3xl font-bold mb-4">Welcome Back</h2>
                        <p className="text-blue-100/90 leading-relaxed">
                            Sign in to access your digital workspace, manage tasks, and collaborate with your team.
                        </p>
                    </div>

                    {/* Decorative Circles */}
                    <div className="absolute top-0 right-0 -mr-20 -mt-20 w-80 h-80 rounded-full bg-indigo-500/30 blur-3xl"></div>
                    <div className="absolute bottom-0 left-0 -ml-20 -mb-20 w-80 h-80 rounded-full bg-blue-500/30 blur-3xl"></div>

                    <div className="relative z-10 flex items-center gap-3 text-sm font-medium bg-white/10 p-4 rounded-xl backdrop-blur-sm border border-white/10">
                        <ShieldCheck size={20} className="text-blue-200" />
                        <span>Secure Enterprise Login</span>
                    </div>
                </div>

                {/* Form Side */}
                <div className="flex-1 p-8 md:p-12 flex flex-col justify-center">
                    <div className="max-w-md mx-auto w-full">
                        <div className="text-center md:text-left mb-10">
                            <h1 className="text-2xl font-bold text-slate-900 mb-2">Sign in to Doptor</h1>
                            <p className="text-slate-500">Please enter your credentials to continue.</p>
                        </div>

                        <form onSubmit={handleSubmit} className="space-y-6">
                            {error && (
                                <motion.div
                                    initial={{ opacity: 0, height: 0 }}
                                    animate={{ opacity: 1, height: 'auto' }}
                                    className="p-4 rounded-xl bg-red-50 text-red-600 text-sm flex items-center gap-3 border border-red-100"
                                >
                                    <AlertCircle size={18} />
                                    {error}
                                </motion.div>
                            )}

                            <div className="space-y-4">
                                <div>
                                    <label className="block text-sm font-medium text-slate-700 mb-1.5">Email Address</label>
                                    <input
                                        type="email"
                                        value={email}
                                        onChange={(e) => setEmail(e.target.value)}
                                        className="w-full px-4 py-3.5 rounded-xl border border-slate-200 focus:border-blue-500 focus:ring-4 focus:ring-blue-500/10 outline-none transition-all bg-slate-50/50 focus:bg-white"
                                        placeholder="name@company.com"
                                        required
                                    />
                                </div>

                                <div>
                                    <div className="flex justify-between items-end mb-1.5">
                                        <label className="block text-sm font-medium text-slate-700">Password</label>
                                        <Link href="/forgot-password" className="text-xs font-medium text-blue-600 hover:text-blue-700 hover:underline">
                                            Forgot password?
                                        </Link>
                                    </div>
                                    <input
                                        type="password"
                                        value={password}
                                        onChange={(e) => setPassword(e.target.value)}
                                        className="w-full px-4 py-3.5 rounded-xl border border-slate-200 focus:border-blue-500 focus:ring-4 focus:ring-blue-500/10 outline-none transition-all bg-slate-50/50 focus:bg-white"
                                        placeholder="••••••••"
                                        required
                                    />
                                </div>
                            </div>

                            <button
                                type="submit"
                                disabled={isLoading}
                                className="w-full py-4 bg-gradient-to-r from-blue-600 to-indigo-600 hover:from-blue-700 hover:to-indigo-700 text-white font-semibold rounded-xl shadow-lg shadow-blue-200 transition-all transform hover:-translate-y-0.5 active:scale-[0.98] disabled:opacity-70 disabled:cursor-not-allowed flex justify-center items-center"
                            >
                                {isLoading ? (
                                    <Loader2 className="animate-spin" size={20} />
                                ) : (
                                    'Sign In'
                                )}
                            </button>
                        </form>

                        <p className="mt-8 text-center text-slate-500 text-sm">
                            Don't have an account?{' '}
                            <Link href="/onboarding" className="text-blue-600 font-semibold hover:text-blue-700 hover:underline">
                                Get Started
                            </Link>
                        </p>
                    </div>
                </div>
            </motion.div>
        </div>
    );
}

'use client';

import { useState, useEffect } from 'react';
import { Plus, Search, Filter, Inbox, Send, Activity, Clock, AlertCircle } from 'lucide-react';
import { filesService, File } from '@/services/files.service';
import FileList from '@/features/office/FileList';
import FileDetails from '@/features/office/FileDetails';
import FileCreateForm from '@/features/office/FileCreateForm';

export default function OfficeFilesPage() {
    const [activeTab, setActiveTab] = useState<'inbox' | 'outbox'>('inbox');
    const [files, setFiles] = useState<File[]>([]);
    const [loading, setLoading] = useState(true);
    const [searchQuery, setSearchQuery] = useState('');
    const [selectedFile, setSelectedFile] = useState<File | null>(null);
    const [showCreateForm, setShowCreateForm] = useState(false);

    useEffect(() => {
        loadFiles();
    }, [activeTab]);

    async function loadFiles() {
        try {
            setLoading(true);
            const data = activeTab === 'inbox'
                ? await filesService.getInbox()
                : await filesService.getOutbox();
            setFiles(data);
        } catch (error) {
            console.error('Failed to load files', error);
            setFiles([]);
        } finally {
            setLoading(false);
        }
    }

    const filteredFiles = files.filter(f =>
        f.subject.toLowerCase().includes(searchQuery.toLowerCase()) ||
        f.file_number.toLowerCase().includes(searchQuery.toLowerCase())
    );

    // Stats Calculation
    const pendingCount = files.filter(f => f.status === 'active').length;
    const urgentCount = files.filter(f => f.priority === 'urgent' || f.priority === 'immediate').length;
    const todayCount = files.filter(f => new Date(f.created_at).toDateString() === new Date().toDateString()).length;

    return (
        <div className="h-full flex flex-col space-y-6">
            {/* Header Area */}
            <div className="flex flex-col md:flex-row md:items-end justify-between gap-4 pb-4 border-b border-slate-200">
                <div>
                    <h1 className="text-3xl font-light text-slate-900 tracking-tight">e-Dak Files</h1>
                    <p className="text-slate-500 mt-1 font-light">Digital file tracking and correspondence system</p>
                </div>
                <button
                    onClick={() => setShowCreateForm(true)}
                    className="px-6 py-2.5 bg-slate-900 text-white hover:bg-slate-800 transition-colors flex items-center gap-2 rounded-sm shadow-sm"
                >
                    <Plus size={18} />
                    <span>Create File</span>
                </button>
            </div>

            {/* Stats Overview */}
            <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                <StatCard
                    label="Pending Actions"
                    value={pendingCount}
                    icon={Activity}
                    color="text-indigo-600"
                />
                <StatCard
                    label="Urgent Priority"
                    value={urgentCount}
                    icon={AlertCircle}
                    color="text-orange-600"
                />
                <StatCard
                    label="Received Today"
                    value={todayCount}
                    icon={Clock}
                    color="text-emerald-600"
                />
            </div>

            {/* Main Content Area */}
            <div className="flex-1 flex flex-col bg-white border border-slate-200 shadow-sm rounded-sm overflow-hidden">
                {/* Toolbar */}
                <div className="flex flex-col sm:flex-row items-center justify-between p-4 border-b border-slate-100 gap-4">
                    {/* Minimal Tabs */}
                    <div className="flex bg-slate-100/50 p-1 rounded-sm border border-slate-100">
                        <TabButton
                            active={activeTab === 'inbox'}
                            onClick={() => setActiveTab('inbox')}
                            icon={Inbox}
                            label="Inbox"
                            count={activeTab === 'inbox' ? files.length : undefined}
                        />
                        <TabButton
                            active={activeTab === 'outbox'}
                            onClick={() => setActiveTab('outbox')}
                            icon={Send}
                            label="Outbox"
                        />
                    </div>

                    {/* Search & Filter */}
                    <div className="flex w-full sm:w-auto gap-2">
                        <div className="relative group flex-1 sm:flex-none">
                            <Search size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 group-focus-within:text-slate-600 transition-colors" />
                            <input
                                type="text"
                                placeholder="Search files..."
                                value={searchQuery}
                                onChange={(e) => setSearchQuery(e.target.value)}
                                className="w-full sm:w-64 pl-9 pr-4 py-2 bg-white border border-slate-200 focus:border-slate-400 rounded-sm text-sm outline-none transition-all placeholder:text-slate-400 font-light"
                            />
                        </div>
                        <button className="p-2 border border-slate-200 bg-white hover:bg-slate-50 text-slate-500 hover:text-slate-700 rounded-sm transition-colors">
                            <Filter size={16} />
                        </button>
                    </div>
                </div>

                {/* File List */}
                <div className="flex-1 overflow-auto bg-slate-50/30 p-4">
                    {loading ? (
                        <div className="space-y-3">
                            {[1, 2, 3].map((i) => (
                                <div key={i} className="bg-white h-20 rounded-sm border border-slate-100 animate-pulse" />
                            ))}
                        </div>
                    ) : (
                        <FileList
                            files={filteredFiles}
                            onFileClick={setSelectedFile}
                        />
                    )}
                </div>
            </div>

            {/* Modals */}
            {selectedFile && (
                <FileDetails
                    fileId={selectedFile.id}
                    onClose={() => setSelectedFile(null)}
                    onUpdate={loadFiles}
                />
            )}

            {showCreateForm && (
                <FileCreateForm
                    onClose={() => setShowCreateForm(false)}
                    onSuccess={loadFiles}
                />
            )}
        </div>
    );
}

function StatCard({ label, value, icon: Icon, color }: any) {
    return (
        <div className="bg-white p-4 border border-slate-200 rounded-sm shadow-sm flex items-center justify-between group hover:border-slate-300 transition-all">
            <div>
                <p className="text-xs font-medium text-slate-500 uppercase tracking-wider">{label}</p>
                <p className="text-2xl font-light text-slate-900 mt-1">{value}</p>
            </div>
            <div className={`p-2.5 bg-slate-50 rounded-sm ${color} group-hover:bg-opacity-80 transition-colors`}>
                <Icon size={20} />
            </div>
        </div>
    );
}

function TabButton({ active, onClick, icon: Icon, label, count }: any) {
    return (
        <button
            onClick={onClick}
            className={`
                flex items-center gap-2 px-4 py-1.5 rounded-sm text-sm transition-all
                ${active
                    ? 'bg-white text-slate-900 shadow-sm font-medium'
                    : 'text-slate-500 hover:text-slate-700 hover:bg-slate-200/50'
                }
            `}
        >
            <Icon size={16} />
            {label}
            {count !== undefined && (
                <span className={`text-[10px] px-1.5 py-0.5 rounded-sm ml-1 ${active ? 'bg-slate-100 text-slate-700' : 'bg-slate-200 text-slate-600'}`}>
                    {count}
                </span>
            )}
        </button>
    );
}

"use client";

import { Search, Bell, ChevronDown, Building2, Shield } from 'lucide-react';
import { Button } from '@doptor/shared';
import { useRole, UserRole } from '@/features/auth/RoleContext';

export function Header() {
    const { role, setRole } = useRole();

    const roles: UserRole[] = ['super_admin', 'org_admin', 'manager', 'staff', 'student'];

    return (
        <header className="h-16 px-4 md:px-6 border-b border-slate-200 flex items-center justify-between bg-white/80 backdrop-blur-xl sticky top-0 z-10">
            {/* Left: Org Switcher */}
            <div className="flex items-center gap-4">
                <button className="flex items-center gap-2 hover:bg-slate-50 p-2 rounded-lg transition-colors border border-transparent hover:border-slate-200">
                    <div className="w-8 h-8 bg-primary-100 rounded-lg flex items-center justify-center text-primary-600">
                        <Building2 size={18} />
                    </div>
                    <div className="hidden md:block text-left">
                        <p className="text-sm font-bold text-slate-900 leading-none">Acme Corp</p>
                        <p className="text-xs text-slate-500">Organisation</p>
                    </div>
                    <ChevronDown size={16} className="text-slate-400" />
                </button>
            </div>

            {/* Center: Search (Desktop) */}
            <div className="hidden md:flex items-center gap-4 w-96">
                <div className="relative w-full group">
                    <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 group-focus-within:text-primary-500 transition-colors" size={18} />
                    <input
                        type="text"
                        placeholder="Search tasks, docs, people..."
                        className="w-full bg-slate-50 border border-slate-200 rounded-xl py-2 pl-10 pr-4 text-sm text-slate-900 focus:outline-none focus:ring-2 focus:ring-primary-500/20 focus:border-primary-500 transition-all placeholder:text-slate-400"
                    />
                </div>
            </div>

            {/* Right: Actions & Profile */}
            <div className="flex items-center gap-3">
                {/* Role Switcher (Dev Mode) */}
                <div className="hidden md:flex items-center gap-2 mr-2">
                    <select
                        value={role}
                        onChange={(e) => setRole(e.target.value as UserRole)}
                        className="text-xs border border-slate-200 rounded-lg px-2 py-1 bg-slate-50 text-slate-600 focus:outline-none focus:border-primary-500"
                    >
                        {roles.map(r => (
                            <option key={r} value={r}>{r.replace('_', ' ').toUpperCase()}</option>
                        ))}
                    </select>
                </div>

                {/* Role Badge */}
                <div className="hidden md:flex items-center gap-1.5 px-2.5 py-1 rounded-full bg-amber-50 border border-amber-100 text-amber-700 text-xs font-semibold">
                    <Shield size={12} />
                    <span>{role.replace('_', ' ')}</span>
                </div>

                <button className="relative p-2 text-slate-400 hover:text-slate-600 transition-colors rounded-lg hover:bg-slate-100">
                    <Bell size={20} />
                    <span className="absolute top-2 right-2 w-2 h-2 rounded-full bg-red-500 border-2 border-white"></span>
                </button>

                <div className="w-8 h-8 rounded-full bg-slate-200 overflow-hidden border border-slate-300">
                    <img src="https://ui-avatars.com/api/?name=John+Doe&background=random" alt="Profile" className="w-full h-full object-cover" />
                </div>
            </div>
        </header>
    );
}
